#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
int n,m,a[MAXN],b[MAXN],w,t,sum[MAXN],mid;
bool dfs(int x, int l)
{
	if(t-w<sum[mid])return false;
	if(x==0)return true;
	bool flag=0;
	FOR(i,l,n)
	{
		if(a[i]>=b[x])
		{
			a[i]-=b[x];
			if(a[i]<b[1])w+=a[i];
			if(b[x-1]==b[x])flag=dfs(x-1,i);
			else flag=dfs(x-1,1);
			if(a[i]<b[1])w-=a[i];
			a[i]+=b[x];
			if(flag)return true;
		}
	}
	return false;
}
signed main(void)
{
	n=read();
	FOR(i,1,n)
	{
		a[i]=read(),t+=a[i];	
	}
	m=read();
	FOR(i,1,m)
	{
		b[i]=read();
	}
	sort(b+1,b+m+1);
	FOR(i,1,m)
	{
		sum[i]=sum[i-1]+b[i];
	}
	wh(sum[m]>t&&m)--m;
	int l=0,r=m;
	wh(l<=r)
	{
		mid=(l+r)/2;
		if(dfs(mid,1))l=mid+1;
		else r=mid-1;
	}
	write(l-1);
	return false;
}
